var rand;
while(1) {
rand = dwrand() % (max - min + 1) + min;
if(rand == ban) {
continue;
}
return rand;
}
}

function AdvancedRand2(min, max, ban) { // for single ban only
if(min > ban || max < ban) {
return (dwrand() % (max - min + 1) + min);
}
const rand = dwrand() % (max - min) + min;
if(rand == ban) {
return max;
}
return rand;
}

