function BuildResetXEPD(unitEPD){
// 전역 함수 없이 즉석 범위체크
if (unitEPD == 0) return;
if (unitEPD < EPD(0x59CCA8) || unitEPD >= EPD(0x6283E8)) return;

SetMemoryXEPD(unitEPD + 38, SetTo, 14942436, 0xFFFFFFFF);
SetMemoryXEPD(unitEPD + 39, SetTo, 14942436, 0xFFFFFFFF);
SetMemoryXEPD(unitEPD + 40, SetTo, 228, 0xFFFF);
SetMemoryXEPD(unitEPD + 41, SetTo, 131072, 0xFFFF0000);
}

function BuildCheckXEPD(unitEPD ,Unit){
if (unitEPD == 0) return false;
if (unitEPD < EPD(0x59CCA8) || unitEPD >= EPD(0x6283E8)) return false;

const mulUnit = Unit * 65536;

if (MemoryXEPD(unitEPD + 38, Exactly, Unit, 0xFFFF)) return true;
if (MemoryXEPD(unitEPD + 38, Exactly, mulUnit, 0xFFFF0000)) return true;
if (MemoryXEPD(unitEPD + 39, Exactly, Unit, 0xFFFF)) return true;
if (MemoryXEPD(unitEPD + 39, Exactly, mulUnit, 0xFFFF0000)) return true;
