function CheckAndCancel(targetEPD, unitID) {
if (targetEPD == 0) return false;
if (targetEPD < EPD(0x59CCA8) || targetEPD >= EPD(0x6283E8)) return false;

if (!BuildCheckXEPD(targetEPD, unitID)) return false;

BuildResetXEPD(targetEPD);

if (MemoryEPD(targetEPD + 0xEC / 4, AtLeast, 1)) {
const buildPTR = dwread_epd(targetEPD + 0xEC / 4);

// buildPTR도 즉석 범위체크 (PTR은 4바이트 주소)
if (buildPTR != 0 && buildPTR >= 0x59CCA8 && buildPTR < 0x6283E8) {
bwrite(buildPTR + 0x4D, 0);
}
}

return true;
}

